#!/usr/bin/env node
/* global process */
import { spawnSync } from 'node:child_process';
import { resolve } from 'node:path';

function parseArgs(argv) {
  const out = {
    relayUrl: undefined,
    relayRoom: undefined,
    relayKey: undefined,
    relayClientId: undefined,
    relayProtocol: undefined,
    relayMode: undefined,
    relayProduct: undefined,
    readyStrategy: undefined,
    ambientSubstrate: 'monster',
    ambientRuntimeId: 'gnosis://monster/dashrelay',
    dryRun: false,
    forward: [],
  };

  let i = 0;
  while (i < argv.length) {
    const arg = argv[i];
    if (arg === '--' && i === 0) {
      i += 1;
      continue;
    }
    if (arg === '--') {
      out.forward = argv.slice(i + 1);
      break;
    }
    if (!arg?.startsWith('--')) {
      out.forward = argv.slice(i);
      break;
    }

    const [flag, inlineValue] = arg.split('=', 2);
    const takeValue = () => {
      if (inlineValue !== undefined) return inlineValue;
      const next = argv[i + 1];
      if (next === undefined || next === '--') {
        throw new Error(`${flag} requires a value`);
      }
      i += 1;
      return next;
    };

    switch (flag) {
      case '--relay-url':
        out.relayUrl = takeValue();
        break;
      case '--relay-room':
        out.relayRoom = takeValue();
        break;
      case '--relay-key':
        out.relayKey = takeValue();
        break;
      case '--relay-client-id':
        out.relayClientId = takeValue();
        break;
      case '--relay-protocol':
        out.relayProtocol = takeValue();
        break;
      case '--relay-mode':
        out.relayMode = takeValue();
        break;
      case '--relay-product':
        out.relayProduct = takeValue();
        break;
      case '--ready-strategy':
        out.readyStrategy = takeValue();
        break;
      case '--ambient-substrate':
        out.ambientSubstrate = takeValue();
        break;
      case '--ambient-runtime-id':
        out.ambientRuntimeId = takeValue();
        break;
      case '--dry-run':
        out.dryRun = true;
        break;
      default:
        out.forward.push(arg, ...argv.slice(i + 1));
        i = argv.length;
        break;
    }
    i += 1;
  }

  return out;
}

function pickEnv(name, cliValue, fallbackNames = []) {
  if (cliValue && cliValue.trim()) return cliValue.trim();
  for (const fallback of fallbackNames) {
    const value = process.env[fallback];
    if (value && value.trim()) return value.trim();
  }
  return undefined;
}

function printUsage() {
  process.stderr.write(
    [
      'Usage: monster-dashrelay.mjs [relay flags] -- <monster args...>',
      '',
      'Relay flags:',
      '  --relay-url <url>         DashRelay WebSocket/HTTP URL',
      '  --relay-room <room>       DashRelay room name (default entropy; env fallback too)',
      '  --relay-key <key>         Optional DashRelay API key',
      '  --relay-client-id <id>     Optional client id',
      '  --relay-protocol <proto>   Relay protocol (default dashrelay-v1)',
      '  --relay-mode <mode>       Relay join mode (default qdoc-authoritative)',
      '  --relay-product <name>    Relay product label (default aeon-relay)',
      '  --ready-strategy <mode>   joined | snapshot (default snapshot)',
      '  --ambient-substrate <s>   Ambient substrate label (default monster)',
      '  --ambient-runtime-id <id> Ambient runtime id (default gnosis://monster/dashrelay)',
      '  --dry-run                 Print the resolved env and exit',
      '',
      'If the relay flags are omitted, the script reads GNOSIS_DASHRELAY_*',
      'and DASHRELAY_* from the current environment, including the room name.',
    ].join('\n') + '\n'
  );
}

const parsed = parseArgs(process.argv.slice(2));
const relayUrl = pickEnv('GNOSIS_DASHRELAY_URL', parsed.relayUrl, [
  'GNOSIS_DASHRELAY_URL',
  'DASHRELAY_URL',
  'GNOSIS_AEON_RELAY_URL',
  'AEON_RELAY_URL',
]);
const relayRoom =
  pickEnv('GNOSIS_DASHRELAY_ROOM', parsed.relayRoom, [
    'GNOSIS_DASHRELAY_ROOM',
    'DASHRELAY_ROOM',
    'GNOSIS_AEON_RELAY_ROOM',
    'AEON_RELAY_ROOM',
  ]) ?? 'entropy';
if (!relayUrl) {
  printUsage();
  process.exit(1);
}

const relayProtocol =
  pickEnv('GNOSIS_DASHRELAY_PROTOCOL', parsed.relayProtocol, [
    'GNOSIS_DASHRELAY_PROTOCOL',
    'DASHRELAY_PROTOCOL',
    'GNOSIS_AEON_RELAY_PROTOCOL',
    'AEON_RELAY_PROTOCOL',
  ]) ?? 'dashrelay-v1';
const relayMode =
  pickEnv('GNOSIS_DASHRELAY_MODE', parsed.relayMode, [
    'GNOSIS_DASHRELAY_MODE',
    'DASHRELAY_MODE',
    'GNOSIS_AEON_RELAY_MODE',
    'AEON_RELAY_MODE',
  ]) ?? 'qdoc-authoritative';
const relayProduct =
  pickEnv('GNOSIS_DASHRELAY_PRODUCT', parsed.relayProduct, [
    'GNOSIS_DASHRELAY_PRODUCT',
    'DASHRELAY_PRODUCT',
    'GNOSIS_AEON_RELAY_PRODUCT',
    'AEON_RELAY_PRODUCT',
  ]) ?? 'aeon-relay';
const readyStrategy =
  pickEnv('GNOSIS_DASHRELAY_READY_STRATEGY', parsed.readyStrategy, [
    'GNOSIS_DASHRELAY_READY_STRATEGY',
    'DASHRELAY_READY_STRATEGY',
  ]) ?? 'snapshot';
const relayKey = pickEnv('GNOSIS_DASHRELAY_KEY', parsed.relayKey, [
  'GNOSIS_DASHRELAY_KEY',
  'DASHRELAY_API_KEY',
  'GNOSIS_AEON_RELAY_KEY',
  'AEON_RELAY_KEY',
]);
const relayClientId = pickEnv(
  'GNOSIS_DASHRELAY_CLIENT_ID',
  parsed.relayClientId,
  [
    'GNOSIS_DASHRELAY_CLIENT_ID',
    'DASHRELAY_CLIENT_ID',
    'GNOSIS_AEON_RELAY_CLIENT_ID',
    'AEON_RELAY_CLIENT_ID',
  ]
);

const env = {
  ...process.env,
  GNOSIS_AMBIENT_SUBSTRATE: parsed.ambientSubstrate,
  GNOSIS_AMBIENT_RUNTIME_ID: parsed.ambientRuntimeId,
  GNOSIS_DASHRELAY_URL: relayUrl,
  DASHRELAY_URL: relayUrl,
  GNOSIS_AEON_RELAY_URL: relayUrl,
  AEON_RELAY_URL: relayUrl,
  GNOSIS_DASHRELAY_ROOM: relayRoom,
  DASHRELAY_ROOM: relayRoom,
  GNOSIS_AEON_RELAY_ROOM: relayRoom,
  AEON_RELAY_ROOM: relayRoom,
  GNOSIS_DASHRELAY_PROTOCOL: relayProtocol,
  GNOSIS_DASHRELAY_MODE: relayMode,
  GNOSIS_DASHRELAY_PRODUCT: relayProduct,
  GNOSIS_DASHRELAY_READY_STRATEGY: readyStrategy,
};

if (relayKey) {
  env.GNOSIS_DASHRELAY_KEY = relayKey;
  env.DASHRELAY_API_KEY = relayKey;
  env.GNOSIS_AEON_RELAY_KEY = relayKey;
  env.AEON_RELAY_KEY = relayKey;
}

if (relayClientId) {
  env.GNOSIS_DASHRELAY_CLIENT_ID = relayClientId;
  env.DASHRELAY_CLIENT_ID = relayClientId;
  env.GNOSIS_AEON_RELAY_CLIENT_ID = relayClientId;
  env.AEON_RELAY_CLIENT_ID = relayClientId;
}

const monsterBin = resolve(process.cwd(), 'bin/monster');
const monsterArgs = parsed.forward;

if (parsed.dryRun) {
  process.stdout.write(
    JSON.stringify(
      {
        monsterBin,
        monsterArgs,
        relay: {
          url: relayUrl,
          room: relayRoom,
          protocol: relayProtocol,
          mode: relayMode,
          product: relayProduct,
          readyStrategy,
        },
        ambient: {
          substrate: parsed.ambientSubstrate,
          runtimeId: parsed.ambientRuntimeId,
        },
      },
      null,
      2
    ) + '\n'
  );
  process.exit(0);
}

const result = spawnSync(monsterBin, monsterArgs, {
  env,
  stdio: 'inherit',
});

if (result.error) {
  throw result.error;
}

process.exit(result.status ?? 1);
